        await GetOrCreateModule(new TrainingModule
        {
            Title = "Approvals — Advanced Reference",
            Slug = "approvals-reference",
            Summary = "Advanced reference notes: how an entity enters the inbox (submit + threshold matching), model-vs-UI gaps (delegation/history/active-toggle/delete), and the Admin-vs-Manager write split.",
